                Effects:    rowsFromC2(c2.ItemsFor(snapToC2(wResume.Effects), wResume.Turn)),
                Records:    recPath,
                Log:        logPath,
        }, nil
}

func flushRows(recPath, logPath, name string, moves []MoveRow) {
        rec, _ := os.Create(recPath)
        defer rec.Close()
        for _, m := range moves {
